    volumen_captado_l numeric(14,4) DEFAULT 0 NOT NULL,
    volumen_predicho_l numeric(14,4) DEFAULT 0 NOT NULL,
    eficiencia_riego numeric(6,2),
    total_alertas integer DEFAULT 0 NOT NULL,
    resumen text,
    generado_por_ci character varying(20),
    fecha_generacion timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT chk_reportes_semanales_periodo CHECK ((periodo_fin >= periodo_inicio)),
    CONSTRAINT chk_reportes_semanales_valores CHECK (((volumen_captado_l >= (0)::numeric) AND (volumen_predicho_l >= (0)::numeric) AND (total_alertas >= 0)))
);


