--
-- Name: vista_reporte_alertas_invernadero; Type: VIEW; Schema: public; Owner: ruper
--

CREATE VIEW public.vista_reporte_alertas_invernadero AS
 SELECT a.id AS alerta_id,
    i.invernadero_id,
    a.tipo_alerta,
    a.mensaje,
    a.fecha_generacion
   FROM (public.alertas a
     JOIN public.alertas_invernaderos i ON ((a.id = i.alerta_id)));


ALTER VIEW public.vista_reporte_alertas_invernadero OWNER TO ruper;

--
-- Name: vista_reporte_inventario_dispositivos; Type: VIEW; Schema: public; Owner: ruper
--

CREATE VIEW public.vista_reporte_inventario_dispositivos AS
 SELECT d.id AS dispositivo_id,
    d.codigo,
    d.nombre,
    t.nombre AS tipo_dispositivo,
    d.estado_dispositivo_id
   FROM (public.dispositivos d
     JOIN public.tipos_dispositivo t ON ((d.tipo_dispositivo_id = t.id)));


ALTER VIEW public.vista_reporte_inventario_dispositivos OWNER TO ruper;

--
-- Name: vista_reporte_lecturas_sensor; Type: VIEW; Schema: public; Owner: ruper
--

CREATE VIEW public.vista_reporte_lecturas_sensor AS
 SELECT ls.id AS lectura_id,
    s.codigo AS sensor_codigo,
    s.nombre AS sensor_nombre,
    ls.valor AS lectura_valor,
    ls.timestamp_lectura AS fecha_lectura
   FROM (public.lecturas_sensor ls
     JOIN public.sensores s ON ((ls.sensor_id = s.id)));


ALTER VIEW public.vista_reporte_lecturas_sensor OWNER TO ruper;

--
-- Name: vista_reporte_predicciones_agua; Type: VIEW; Schema: public; Owner: ruper
--

CREATE VIEW public.vista_reporte_predicciones_agua AS
 SELECT p.id AS prediccion_id,
    fa.nombre AS fuente_agua,
    m.nombre AS modelo_usado,
    p.fecha_objetivo,
    p.volumen_predicho_l
   FROM ((public.predicciones_ml p
     JOIN public.modelos_ml m ON ((p.modelo_ml_id = m.id)))
     JOIN public.fuentes_agua fa ON ((p.fuente_agua_id = fa.id)));


ALTER VIEW public.vista_reporte_predicciones_agua OWNER TO ruper;

--
-- Name: vista_reporte_riego_ejecutado; Type: VIEW; Schema: public; Owner: ruper
--

CREATE VIEW public.vista_reporte_riego_ejecutado AS
 SELECT dr.id AS decision_id,
    dri.invernadero_id,
    dr.texto_decision,
    er.inicio_evento,
    er.duracion_segundos
   FROM ((public.decisiones_riego dr
     JOIN public.decisiones_riego_invernaderos dri ON ((dr.id = dri.decision_riego_id)))
     JOIN public.eventos_riego er ON ((dr.id = er.decision_riego_id)));


ALTER VIEW public.vista_reporte_riego_ejecutado OWNER TO ruper;

